import java.io.*;
import java.util.*;

public class Main {
    private static final class FastScanner {
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private final InputStream in;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            do {
                c = readByte();
                if (c == -1) return Long.MIN_VALUE;
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = readByte();
            }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        int T = (int) fs.nextLong();
        for (int tc = 0; tc < T; tc++) {
            int N = (int) fs.nextLong();
            long[] boys = new long[N];
            long[] girls = new long[N];
            for (int i = 0; i < N; i++) boys[i] = fs.nextLong();
            for (int i = 0; i < N; i++) girls[i] = fs.nextLong();
            Arrays.sort(boys); // ascending
            Arrays.sort(girls); // ascending, will use from end for descending
            long maxSum = 0L;
            for (int i = 0; i < N; i++) {
                long sum = boys[i] + girls[N - 1 - i];
                if (sum > maxSum) maxSum = sum;
            }
            sb.append(maxSum);
            if (tc < T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

